// existing users get an automatic onupgradeneeded migration via openDb.
const DB_VERSION = 3;
const STATE_STORE = 'state';
const LOG_STORE = 'log';
const PROGRAM_STORE = 'program';
const INVENTORY_STORE = 'inventory';
