export function getDb(): Promise<IDBDatabase> {
  if (!dbPromise) {
    dbPromise = openDb({
      name: DB_NAME,
      version: DB_VERSION,
      stores: [
        { name: STATE_STORE },
        { name: LOG_STORE },
        { name: PROGRAM_STORE },
        { name: INVENTORY_STORE },
      ],
    });
  }
  return dbPromise;
}

export const DEFAULT_STATE: WorkoutState = { globalDay: 1, currentPhase: 'p1' };

